scwin.vCurDate;
scwin.vQryStDt;
scwin.vQryEndDt;

scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "SD070", compID : "acb_taxnClsCd" },
        { grpCd : "FM018", compID : "gr_dnTrustTaxInvoice:reqPayMthdCd,acb_payMthdCd" },
    ];
    $c.data.setCommonCode(codeOptions, scwin.setCommonCodeCallBack);

    scwin.vCurDate  = $c.date.getServerDateTime("yyyyMMdd");                 // 서버를 기준으로 현재 날짜 반환
    scwin.vQryStDt  = scwin.vCurDate.substring(0, 6) + "01";                 // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
    scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + $c.date.getLastDateOfMonth(scwin.vCurDate.substring(0,6));  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자) 

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":50});
};

scwin.setCommonCodeCallBack = function(){
    // 회계일자 : 20200101 20200130 부가세구분 : 영세기타
    $p.setTimeout(function() {

        ica_qryConDtFm.setValue(scwin.vQryStDt);
        ica_qryConDtTo.setValue(scwin.vQryEndDt);
        // CERTI^거래명세서일자,SPPLY^세금계산서일자,POST^회계일자
        acb_qryDtConKnd.setValue("CERTI");
        acb_taxnClsCd.setSelectedIndex(2)
        acb_payMthdCd.setSelectedIndex(1);
        rd_acctGubun.setValue(0);
        ed_homeClntNo.focus();

        // acb_qryDtConKnd.setValue("POST");
        // ica_qryConDtFm.setValue("20200101");
        // ica_qryConDtTo.setValue("20200130");
        // acb_taxnClsCd.setValue("03");

        // // ja_210_03_02p
        // acb_qryDtConKnd.setValue("CERTI")
        // ica_qryConDtFm.setValue("20191101");
        // ica_qryConDtTo.setValue("20200101");
        // acb_taxnClsCd.setValue("03");

    }, {"delay":150});
};

//-------------------------------------------------------------------------
// 거래명세서 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    //조회시작일자가 더 클경우 체크
    if (!await $c.gus.cfIsAfterDate(ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }
    $c.sbm.execute(sbm_searchCertiList);

};

//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    switch (disGubun) {
        case 1:
            //소속거래처
            udc_homeClnt.setSelectId('retrieveSubsidaryClntList');
            udc_homeClnt.cfCommonPopUp(scwin.udc_homeClnt_callBackFunc         // XML상의 SELECT ID
                                      ,pCode                              // 화면에서의 ??? Code Element의  Value
                                      ,pName                              // 화면에서의 ??? Name Element의  Value
                                      ,pClose                             // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                      ,'5'                                // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                      ,null                               // Title순서
                                      ,'150,170'                          // 보여주는 각 컬럼들의 폭
                                      ,null                               // 컬럼중에서 숨기는    컬럼 지정
                                      ,null                               // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                      ,null                               // POP-UP뛰을때 원도우의   사용자 정의  폭
                                      ,null                               // POP-UP뛰을때 우도우의   사용자 정의  높이
                                      ,null                               // 윈도우 위치 Y좌표
                                      ,null                               // 윈도우 위치 X좌표
                                      ,null                               // 중복체크여부   ("F")
                                      ,pAllSearch                         // 전체검색허용여부 ("F")
                                      ,"소속거래처,거래처코드,거래처명"         // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
        case 2:
            //미지급거래처
            udc_acctClnt.setSelectId('retrieveSubsidaryClntList');
            udc_acctClnt.cfCommonPopUp(scwin.udc_acctClnt_callBackFunc         // XML상의 SELECT ID
                                      ,pCode                              // 화면에서의 ??? Code Element의  Value
                                      ,pName                              // 화면에서의 ??? Name Element의  Value
                                      ,pClose                             // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                      ,'5'                                // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                      ,null                               // Title순서
                                      ,'150,170'                          // 보여주는 각 컬럼들의 폭
                                      ,null                               // 컬럼중에서 숨기는    컬럼 지정
                                      ,null                               // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                      ,null                               // POP-UP뛰을때 원도우의   사용자 정의  폭
                                      ,null                               // POP-UP뛰을때 우도우의   사용자 정의  높이
                                      ,null                               // 윈도우 위치 Y좌표
                                      ,null                               // 윈도우 위치 X좌표
                                      ,null                               // 중복체크여부   ("F")
                                      ,pAllSearch                         // 전체검색허용여부 ("F")
                                      ,"미지급거래처,거래처코드,거래처명"         // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 전표일자, 공급일자 일자일괄적용
//------------------------------------------------------------------------- 
scwin.f_adaptSlipDt = async function (){
    var chkCnt = 0;
    var stPos   = ds_dnTrustTaxInvoice.getRowPosition(); 
    var slipDt  = ds_dnTrustTaxInvoice.getCellData(stPos, "slipDt");
    var spplyDt = ds_dnTrustTaxInvoice.getCellData(stPos, "spplyDt");
    var reqDt   = ds_dnTrustTaxInvoice.getCellData(stPos, "reqDt");

    for(var i = 0 ; i < ds_dnTrustTaxInvoice.getRowCount(); i++){
        if(ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T"){
            ds_dnTrustTaxInvoice.setCellData(i, "slipDt", slipDt);
            ds_dnTrustTaxInvoice.setCellData(i, "spplyDt", spplyDt);
            ds_dnTrustTaxInvoice.setCellData(i, "reqDt", reqDt);
            chkCnt++;
        }
    }
    if(chkCnt == 0){
        await $c.win.alert("선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
        return false;
    }
};

//-------------------------------------------------------------------------
// 전도금 미지급금 계정일괄적용 20170807
//------------------------------------------------------------------------- 
scwin.f_adaptAcctGubun = async function (){
    var chkCnt = 0;

    var gubun = rd_acctGubun.getValue();        // gubun 0:전도금 1:미지급금
    var acctClntNo = ed_acctClntNo.getValue();  // 미지급거래처

    if (gubun == "1" && acctClntNo == "" ){
        await $c.win.alert("미지급금인 경우 미지급거래처를 입력하세요.");
        return;
    }
    //scwin.dataSetDebug(ds_dnTrustTaxInvoice,true);
    for(var i = 0 ; i < ds_dnTrustTaxInvoice.getRowCount(); i++){
        if(ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T"){
            ds_dnTrustTaxInvoice.setCellData(i, "acctGubun", gubun);
            if (gubun=="1"){
                ds_dnTrustTaxInvoice.setCellData(i, "bilgClntNo", acctClntNo);
            } else {
                ds_dnTrustTaxInvoice.setCellData(i, "bilgClntNo", "280161"); //20170822 성원영대리님 요청(전도금-일반계정의 귀속부서만 00915)
            }
            chkCnt++;
        }
    }
    if(chkCnt == 0){
        await $c.win.alert("선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
        return;
    }
};

//-------------------------------------------------------------------------
// 검색영역 Field Clear함.
//-------------------------------------------------------------------------
scwin.f_InitObjects = function () {
    $c.gus.cfInitObjects(tb_mainData);
    scwin.f_SetDefaultData();
};

//-------------------------------------------------------------------------
// 일괄생성
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    ds_sellingEvidenceSave.removeAll();

    // Save DataSet Setting
    var chkCreateCnt = 0; /*일괄생성 사이즈체크*/
    for (var i = 0 ; i < ds_dnTrustTaxInvoice.getRowCount(); i++) {
        if (ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T") {
            if(ds_dnTrustTaxInvoice.getCellData(i, "slipNo") == null || ds_dnTrustTaxInvoice.getCellData(i, "slipNo") == ""){
                scwin.f_SetDataSet(chkCreateCnt, i); 	             	
                chkCreateCnt++;
            }else{
                await $c.win.alert((i+1)+"번째 행은 이미 전표가 생성된 건입니다. 다시 확인해주십시오.");
                return false;
            }            	
        }
    }
    if(chkCreateCnt == 0){
        await $c.win.alert("선택된 행이 없습니다. 일괄생성할 행들을 선택해 주십시오.");
        return false;
    }else{
        //scwin.dataSetDebug(ds_sellingEvidenceSave,true);
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// Save or Del DataSet Setting
//-------------------------------------------------------------------------
scwin.f_SetDataSet = function (chkCreateCnt, row){
    ds_sellingEvidenceSave.insertRow();
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "choice"               , "T");
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "slipDt"               , ds_dnTrustTaxInvoice.getCellData(row, "slipDt"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "slipNo"               , ds_dnTrustTaxInvoice.getCellData(row, "slipNo"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "summary"              , ds_dnTrustTaxInvoice.getCellData(row, "summary"));              
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "spplyDt"              , ds_dnTrustTaxInvoice.getCellData(row, "spplyDt"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "clntNo"               , ds_dnTrustTaxInvoice.getCellData(row, "clntNo"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "crn"                  , ds_dnTrustTaxInvoice.getCellData(row, "crn"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "postDt"               , ds_dnTrustTaxInvoice.getCellData(row, "postDt"));             
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "collMoneyAcctDeptCd"  , ds_dnTrustTaxInvoice.getCellData(row, "collMoneyAcctDeptCd"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "bilgLodeptCd"         , ds_dnTrustTaxInvoice.getCellData(row, "bilgLodeptCd"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "acctDeptCd"           , ds_dnTrustTaxInvoice.getCellData(row, "acctDeptCd"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "bilgClntNo"           , ds_dnTrustTaxInvoice.getCellData(row, "bilgClntNo"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "bilgClntNm"           , ds_dnTrustTaxInvoice.getCellData(row, "bilgClntNm"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "crcCd"                , "KRW");
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "receptClsCd"          , "01");                                                    // 영수
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "evidRglClsCd"         , "01");                                                    // 세금계산서 상태 : 01 '정상', 02 '적자', 99 '삭제'
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "certiNo"              , ds_dnTrustTaxInvoice.getCellData(row, "certiNo"));        // 거래명세서번호
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "certiCnt"             , "1");                                                     // 거래명세서건수
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "bilgAmt"              , "0");
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "bilgAmtFcrc"          , "0");
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "fcrcBilgAmt"          , "0");
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "spplyAmt"             , ds_dnTrustTaxInvoice.getCellData(row, "spplyAmt"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "vatAmt"               , ds_dnTrustTaxInvoice.getCellData(row, "vatAmt"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "fmlaPatternCd"        , "K5");
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "fmlaClsCd"            , "01");
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "dcsnClsCd"            , "3");
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "taxnClsCd"            , "03");                                                    // 부가세 구분 : 기타
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "slipKndCd"            , "K05");
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "bilgCrn"              , ds_dnTrustTaxInvoice.getCellData(row, "bilgCrn"));         // 지급처 사업자번호
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "reqPayMthdCd"         , ds_dnTrustTaxInvoice.getCellData(row, "reqPayMthdCd"));    // 지급방법
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "reqDt"                , ds_dnTrustTaxInvoice.getCellData(row, "reqDt"));           // 지급일자
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "sellDrAcctCd"         , ds_dnTrustTaxInvoice.getCellData(row, "sellDrAcctCd"));
    ds_sellingEvidenceSave.setCellData(chkCreateCnt, "acctGubun"            , ds_dnTrustTaxInvoice.getCellData(row, "acctGubun"));
};

scwin.dataSetDebug = async function (dataSet, isDebug){
    if(isDebug == true){
        var obj = dataSet;
        var str = "[[[["+ obj.id+"]]]]]\n";
        for (var dsRow = 1; dsRow <= obj.CountRow; dsRow++ ){
        for ( var dsCol = 1; dsCol <= obj.CountColumn; dsCol++ ){
            str += "["+obj.ColumnId(dsCol)+"] "+obj.NameValue(dsRow, obj.ColumnId(dsCol))+", "
        }
        str += "\n\n";
        }
        await $c.win.alert( str );
    }
}

//-------------------------------------------------------------------------
// 지급방법 일괄적용
//------------------------------------------------------------------------- 
scwin.f_reqPayMthdCd = async function (){
    var gubun = acb_payMthdCd.getValue();   
    var chkCnt = 0;
    for(var i = 0 ; i < ds_dnTrustTaxInvoice.getRowCount(); i++){
        if (ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T"){
            ds_dnTrustTaxInvoice.setCellData(i, "reqPayMthdCd", gubun);
            chkCnt++;
        }
    }
    if (chkCnt == 0){
        await $c.win.alert("선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
        return;
    }
};

