scwin.sbm_searchCertiList_submit = function (e) {
    ds_condition.set("homeClntNo", ed_homeClntNo.getValue());
    ds_condition.set("qryConDtFm", ica_qryConDtFm.getValue());
    ds_condition.set("qryConDtTo", ica_qryConDtTo.getValue());
    ds_condition.set("qryConKnd", acb_qryDtConKnd.getValue());
    ds_condition.set("taxnClsCd", acb_taxnClsCd.getValue());

};

scwin.sbm_searchCertiList_submitdone = async function (e) {
    var rowCnt = ds_dnTrustTaxInvoice.getRowCount();
    txt_totalRows.setValue(rowCnt);
    if (rowCnt == 0){
        if(await $c.gus.cfCheckCreateFlag()){
            $c.gus.cfTurnCreateFlag(false);
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }
    } else {
        gr_dnTrustTaxInvoice.setColumnStyle("button", "text-decoration", "underline");
        gr_dnTrustTaxInvoice.setColumnStyle("button", "color", "blue");
        gr_dnTrustTaxInvoice.setColumnStyle("button", "cursor", "pointer");

        ica_slipCloseYm.setValue(ds_dnTrustTaxInvoice.getCellData(0, "slipCloseYm"));   //회계마감월
        ica_taxCloseYm.setValue(ds_dnTrustTaxInvoice.getCellData(0, "taxCloseYm"));    //세무마감월
    }
};

scwin.sbm_searchCertiList_submiterror = function (e) {

};

