scwin.gr_dnTrustTaxInvoice_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if(columnId == "button"){

		ds_dnTrustTaxInvoice.setCellData(rowIndex, "choice", "T");

		var valueObject = new Object();
		valueObject.pchsClntNo           = ds_dnTrustTaxInvoice.getCellData(rowIndex, "bilgClntNo");
		valueObject.certiNo              = ds_dnTrustTaxInvoice.getCellData(rowIndex, "certiNo");
		valueObject.homeClntNo           = ds_dnTrustTaxInvoice.getCellData(rowIndex, "homeClntNo");    
		valueObject.acctGubun          	 = ds_dnTrustTaxInvoice.getCellData(rowIndex, "acctGubun");    
		valueObject.oldBilgClntNo        = ds_dnTrustTaxInvoice.getCellData(rowIndex, "oldBilgClntNo");
		// 상세화면 호출 
		// var result = window.showModalDialog("/ja/dn/consignmgnt/ja_210_03_02p.jsp", valueObject, 
		//              "dialogWidth:620px; dialogHeight:360px; status:no; scroll:no");      
        let win_url = "/ui/ja/dn/consignmgnt/ja_210_03_02p.xml";
        // let data = {
        //       pchsClntNo           : ds_dnTrustTaxInvoice.getCellData(rowIndex, "bilgClntNo")
        //     , certiNo              : ds_dnTrustTaxInvoice.getCellData(rowIndex, "certiNo")
        //     , homeClntNo           : ds_dnTrustTaxInvoice.getCellData(rowIndex, "homeClntNo")    
        //     , acctGubun            : ds_dnTrustTaxInvoice.getCellData(rowIndex, "acctGubun")    
        //     , oldBilgClntNo        : ds_dnTrustTaxInvoice.getCellData(rowIndex, "oldBilgClntNo")
        // };
        let opts = {
            id : "detailPop"
            , popupName : "대납전표 개별생성"
            , modal : true
            , type : "browserPopup"
            , width : 840
            , height : 436
            , title : "대납전표 개별생성"
        };
        await $c.win.openPopup(win_url, opts, valueObject);                      

        $c.sbm.execute(sbm_searchCertiList);
	}
};

scwin.rd_acctGubun_onviewchange = function (info) {
    //gubun 0:전도금 1:미지급금
	var gubun = rd_acctGubun.getValue();             
	if (gubun == "0"){         //0전도금
		ed_acctClntNo.setValue("");
		ed_acctClntNm.setValue("");
	} else if (gubun == "1"){   //1미지급금

	}
};

scwin.udc_homeClnt_callBackFunc = function(ref){
    if(ref != null){ 
        $c.gus.cfSetReturnValue(ref, ed_homeClntNo, ed_homeClntNm); 
    }
};

scwin.udc_acctClnt_callBackFunc = function(ref){
    if(ref != null){ 
        $c.gus.cfSetReturnValue(ref, ed_acctClntNo, ed_acctClntNm);  
        rd_acctGubun.setValue(1);  
    }
};

scwin.customFormatter_crn = function(value, formatDater, rowIdx, colIdx){
    // ###-##-#####
    var return1 = "";
    if(value.length == 10){
        return1 = $c.gus.cfGetFormatStr(value, "###-##-#####");
    }
    return return1;
};

scwin.gr_dnTrustTaxInvoice_decode1 = function(value, formatDater, rowIdx, colIdx){
    var return1 = "";
    if(ds_dnTrustTaxInvoice.getCellData(rowIdx, "slipNo") == ""){
        if(ds_dnTrustTaxInvoice.getCellData(rowIdx, "acctGubun") == "0"){
            return1 = "전도금";
        }else{
            return1 = "미지급금";
        }
    }
    return return1;
};

scwin.gr_dnTrustTaxInvoice_onbeforecolumnmove = function (info) {
    const validArr = ["choice", "button", "slipNo"];
    const startColumnID = info.startColumnID;
    const endColumnID = info.endColumnID;
    if($.inArray(startColumnID, validArr) > -1) {
        return false;

    }
    if($.inArray(endColumnID, validArr) > -1) {
         return false;
    }
};
